# parse author name if JSON

def author_name(a):
    if a is None:
        return None
    s = str(a)
    if s.strip().lower() == 'none':
        return None
    if s.strip().startswith('{') and '"name"' in s:
        try:
            return json.loads(s).get('name')
        except Exception:
            return s
    return s

